import{_ as e,a as d,b as a}from"./chunks/配置容量限制.DkdWbdOw.js";import{_ as l,o as r,c as i,a2 as o}from"./chunks/framework.DnrXFDHb.js";const f=JSON.parse('{"title":"Добавление канала Cloudflare R2","description":"","frontmatter":{},"headers":[],"relativePath":"ru-RU/upload/cloudflare-r2.md","filePath":"ru-RU/upload/cloudflare-r2.md","lastUpdated":1781962217000}'),n={name:"ru-RU/upload/cloudflare-r2.md"};function c(u,t,b,h,s,g){return r(),i("div",null,[...t[0]||(t[0]=[o('<h1 id="добавление-канала-cloudflare-r2" tabindex="-1">Добавление канала Cloudflare R2 <a class="header-anchor" href="#добавление-канала-cloudflare-r2" aria-label="Permalink to &quot;Добавление канала Cloudflare R2&quot;">​</a></h1><h2 id="когда-это-лучшии-вариант" tabindex="-1">Когда это лучший вариант <a class="header-anchor" href="#когда-это-лучшии-вариант" aria-label="Permalink to &quot;Когда это лучший вариант&quot;">​</a></h2><p>Используйте Cloudflare R2, если:</p><ul><li>сайт ImgBed уже развернут в Cloudflare, и вы хотите хранить файлы в R2 bucket в том же аккаунте;</li><li>не хотите отдельно настраивать S3 endpoint, access key и secret key;</li><li>хотите, чтобы чтение и запись шли через R2 binding в Worker или Pages с минимальной настройкой.</li></ul><p>Коротко:</p><p>R2-канал не создается вручную в админ-панели ImgBed. Сначала нужно привязать R2 bucket к проекту Cloudflare, а имя переменной binding должно быть ровно <code>img_r2</code>.</p><h2 id="что-подготовить-заранее" tabindex="-1">Что подготовить заранее <a class="header-anchor" href="#что-подготовить-заранее" aria-label="Permalink to &quot;Что подготовить заранее&quot;">​</a></h2><ul><li>Аккаунт Cloudflare.</li><li>Уже созданный R2 bucket.</li><li>Права на управление Cloudflare-проектом, где развернут ImgBed.</li></ul><h2 id="настроика-в-cloudflare" tabindex="-1">Настройка в Cloudflare <a class="header-anchor" href="#настроика-в-cloudflare" aria-label="Permalink to &quot;Настройка в Cloudflare&quot;">​</a></h2><h3 id="_1-создаите-r2-bucket" tabindex="-1">1. Создайте R2 bucket <a class="header-anchor" href="#_1-создаите-r2-bucket" aria-label="Permalink to &quot;1. Создайте R2 bucket&quot;">​</a></h3><ol><li>Войдите в Cloudflare Dashboard.</li><li>Откройте <code>R2 Object Storage</code>.</li><li>Нажмите Create bucket.</li><li>Выберите имя bucket, например <code>imgbed</code>.</li></ol><p>В этом bucket будут храниться загруженные файлы.</p><p><img src="'+e+'" alt="Создание R2 bucket" loading="lazy"></p><h3 id="_2-привяжите-bucket-к-проекту-imgbed" tabindex="-1">2. Привяжите bucket к проекту ImgBed <a class="header-anchor" href="#_2-привяжите-bucket-к-проекту-imgbed" aria-label="Permalink to &quot;2. Привяжите bucket к проекту ImgBed&quot;">​</a></h3><p>Место binding зависит от типа развертывания:</p><table tabindex="0"><thead><tr><th>Тип развертывания</th><th>Где настраивается binding</th></tr></thead><tbody><tr><td>Pages</td><td>Current Pages project -&gt; Settings -&gt; Functions -&gt; R2 bucket bindings</td></tr><tr><td>Worker</td><td>Current Worker -&gt; Settings -&gt; Bindings -&gt; R2 bucket bindings</td></tr></tbody></table><p>При добавлении binding важны такие поля:</p><table tabindex="0"><thead><tr><th>Поле</th><th>Значение</th></tr></thead><tbody><tr><td>Variable name</td><td><code>img_r2</code></td></tr><tr><td>R2 bucket</td><td>Выберите созданный bucket.</td></tr></tbody></table><p>Имя переменной должно быть точно <code>img_r2</code>. Загрузка, чтение и удаление файлов R2 зависят именно от этого имени binding.</p><h3 id="_3-разверните-проект-заново" tabindex="-1">3. Разверните проект заново <a class="header-anchor" href="#_3-разверните-проект-заново" aria-label="Permalink to &quot;3. Разверните проект заново&quot;">​</a></h3><p>После сохранения binding повторно разверните ImgBed, чтобы runtime Worker или Pages получил доступ к <code>img_r2</code>.</p><h2 id="что-вы-увидите-в-imgbed" tabindex="-1">Что вы увидите в ImgBed <a class="header-anchor" href="#что-вы-увидите-в-imgbed" aria-label="Permalink to &quot;Что вы увидите в ImgBed&quot;">​</a></h2><p>Когда R2 binding станет доступен, откройте:</p><ol><li>Системные настройки.</li><li>Настройки загрузки.</li><li>Канал <code>Cloudflare R2</code>.</li></ol><p>Система автоматически создает один фиксированный канал:</p><table tabindex="0"><thead><tr><th>Поле</th><th>Фиксированное значение</th></tr></thead><tbody><tr><td>Название канала</td><td><code>Cloudflare R2</code></td></tr><tr><td>Тип канала</td><td><code>cfr2</code></td></tr><tr><td>Режим хранения</td><td><code>binding</code></td></tr><tr><td>Источник конфигурации</td><td>Environment binding</td></tr></tbody></table><p>Это фиксированный канал через binding. Его не нужно создавать кнопкой Add Channel, и его нельзя удалить как обычный канал.</p><h2 id="поля-которые-можно-изменить-в-админ-панели" tabindex="-1">Поля, которые можно изменить в админ-панели <a class="header-anchor" href="#поля-которые-можно-изменить-в-админ-панели" aria-label="Permalink to &quot;Поля, которые можно изменить в админ-панели&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Поле</th><th>Что делает</th><th>Обязательно</th></tr></thead><tbody><tr><td>Enable channel</td><td>Определяет, участвует ли R2 в выборе канала для загрузки.</td><td>Да</td></tr><tr><td>Account ID</td><td>Нужен только при включенных лимитах квоты, когда требуется запрашивать официальное использование R2.</td><td>Рекомендуется при включенных квотах</td></tr><tr><td>Bucket name</td><td>Нужен только при включенных лимитах квоты, когда требуется запрашивать официальное использование R2.</td><td>Рекомендуется при включенных квотах</td></tr><tr><td>Quota limit</td><td>Определяет, учитывается ли емкость канала при выборе хранилища.</td><td>Нет</td></tr><tr><td>Threshold</td><td>Останавливает запись в этот канал после достижения указанного процента использования.</td><td>Да, если включены квоты</td></tr></tbody></table><p>Account ID можно скопировать из панели информации аккаунта в Cloudflare dashboard. Заполняйте его только тогда, когда хотите, чтобы ImgBed запрашивал и контролировал использование квоты R2.</p><p><img src="'+d+'" alt="Получение Account ID" loading="lazy"></p><h2 id="настроика" tabindex="-1">Настройка <a class="header-anchor" href="#настроика" aria-label="Permalink to &quot;Настройка&quot;">​</a></h2><ol><li>Создайте R2 bucket в Cloudflare.</li><li>Откройте настройки Cloudflare для проекта ImgBed.</li><li>Добавьте R2 bucket binding.</li><li>В поле <code>Variable name</code> укажите <code>img_r2</code>.</li><li>Выберите созданный R2 bucket.</li><li>Сохраните binding и повторно разверните ImgBed.</li><li>Вернитесь в ImgBed -&gt; System Settings -&gt; Upload Settings.</li><li>Убедитесь, что канал <code>Cloudflare R2</code> появился и включен.</li></ol><p>Если хотите, чтобы R2 учитывался при выборе канала по доступной емкости, включите quota limit, затем перед сохранением введите Account ID, имя bucket, лимит квоты и threshold.</p><p><img src="'+a+'" alt="Настройка лимитов квоты" loading="lazy"></p><h2 id="как-проверить" tabindex="-1">Как проверить <a class="header-anchor" href="#как-проверить" aria-label="Permalink to &quot;Как проверить&quot;">​</a></h2><ul><li>Фиксированный канал <code>Cloudflare R2</code> появляется в настройках загрузки.</li><li>На карточке канала видно, что он включен.</li><li>Небольшой тестовый файл успешно загружается, а возвращенная ссылка открывается нормально.</li><li>Если при открытии файла появляется <code>R2 database binding is not configured</code>, runtime не получил binding <code>img_r2</code>. Проверьте имя binding в Cloudflare и разверните проект заново.</li></ul>',37)])])}const k=l(n,[["render",c]]);export{f as __pageData,k as default};
